g.script:

const svg = document.querySelector('svg'); // 获取SVG元素
const particles = []; // 存储粒子的数组
const maxParticles = 80; // 粒子数量
const connectDistance = 120; // 连接的最大距离
const maxConnections = 8; // 每个粒子的最大连接数
const dotColor = 'black'; // 圆点颜色（可修改）
const lineColor = '0,0,0'; // 线条颜色（RGB格式，可修改）

class Particle {
    constructor() {
        this.x = Math.random() * 1084; // 随机初始x坐标
        this.y = Math.random() * 322; // 随机初始y坐标
        this.vx = (Math.random() - 0.5) * 0.6; // x方向速度
        this.vy = (Math.random() - 0.5) * 0.6; // y方向速度
        this.connections = 0; // 连接计数
    }
    move() {
        this.x += this.vx; // 更新x坐标
        this.y += this.vy; // 更新y坐标

        // 边界反弹逻辑
        if (this.x <= 0 || this.x >= 1084) this.vx *= -1;
        if (this.y <= 0 || this.y >= 322) this.vy *= -1;

        this.connections = 0; // 重置连接数
    }
}

// 创建粒子
for (let i = 0; i < maxParticles; i++) {
    particles.push(new Particle());
}

function animate() {
    let elements = '<rect x="0" y="0" width="1084" height="322" fill="url(#particlePattern)"></rect>';

    // 遍历粒子并绘制
    for (let i = 0; i < particles.length; i++) {
        particles[i].move();
        elements += `<circle cx="${particles[i].x}" cy="${particles[i].y}" r="3" fill="${dotColor}"/>`;
        let connections = 0;

        // 遍历其他粒子以查找可连接的粒子
        for (let j = i + 1; j < particles.length; j++) {
            let dx = particles[i].x - particles[j].x;
            let dy = particles[i].y - particles[j].y;
            let distance = Math.sqrt(dx * dx + dy * dy);

            // 如果距离在允许范围内并且连接数未超过限制
            if (distance < connectDistance && connections < maxConnections && particles[j].connections < maxConnections) {
                elements += `<line x1="${particles[i].x}" y1="${particles[i].y}" x2="${particles[j].x}" y2="${particles[j].y}" stroke="rgba(${lineColor},${1 - distance / connectDistance})" stroke-width="1"/>`;
                connections++;
                particles[j].connections++;
            }
        }
    }

    svg.innerHTML = elements; // 更新SVG内容
    requestAnimationFrame(animate); // 递归调用，实现动画
}

animate(); // 开始动画
